import React, { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import { useAuth } from "../context/AuthContext";
import { getComplaintsRequest } from "../services/api";

const formatDate = (value) => {
  if (!value) {
    return "-";
  }

  return new Date(value).toLocaleString();
};

function Dashboard() {
  const { user } = useAuth();
  const [complaints, setComplaints] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const isAdmin = user?.role === "ADMIN";

  useEffect(() => {
    const fetchComplaints = async () => {
      setLoading(true);
      setError("");

      try {
        const { data } = await getComplaintsRequest();
        const sorted = [...(Array.isArray(data) ? data : [])].sort(
          (a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0)
        );
        setComplaints(sorted);
      } catch (err) {
        setError(err?.response?.data?.message || "Failed to load dashboard data.");
        setComplaints([]);
      } finally {
        setLoading(false);
      }
    };

    fetchComplaints();
  }, []);

  const summary = useMemo(() => {
    const pending = complaints.filter((item) => item.status === "Pending").length;
    const resolved = complaints.filter((item) => item.status === "Resolved").length;
    const withAttachments = complaints.filter((item) => Boolean(item.fileUrl)).length;
    const thisMonth = complaints.filter((item) => {
      if (!item.createdAt) {
        return false;
      }

      const now = new Date();
      const createdAt = new Date(item.createdAt);
      return (
        createdAt.getMonth() === now.getMonth() && createdAt.getFullYear() === now.getFullYear()
      );
    }).length;

    return {
      total: complaints.length,
      pending,
      resolved,
      withAttachments,
      thisMonth
    };
  }, [complaints]);

  return (
    <>
      <Navbar />

      <div className="page-wrap">
        <div className="container">
          <section className="dashboard-hero mb-4">
            <p className="eyebrow mb-2">Compliance command center</p>
            <h1 className="dashboard-title mb-2">Welcome back, {user?.name || "User"}</h1>
            <p className="dashboard-subtitle mb-0">
              Track complaints, monitor resolution progress, and take action quickly.
            </p>
          </section>

          {error && <div className="alert alert-danger">{error}</div>}

          <div className="row g-3 mb-4">
            <div className="col-6 col-lg-3">
              <div className="stat-card stat-card-1">
                <p>Total Complaints</p>
                <h3>{summary.total}</h3>
              </div>
            </div>
            <div className="col-6 col-lg-3">
              <div className="stat-card stat-card-2">
                <p>Pending</p>
                <h3>{summary.pending}</h3>
              </div>
            </div>
            <div className="col-6 col-lg-3">
              <div className="stat-card stat-card-3">
                <p>Resolved</p>
                <h3>{summary.resolved}</h3>
              </div>
            </div>
            <div className="col-6 col-lg-3">
              <div className="stat-card stat-card-4">
                <p>This Month</p>
                <h3>{summary.thisMonth}</h3>
              </div>
            </div>
          </div>

          <div className="row g-4">
            <div className="col-lg-8">
              <div className="panel-card h-100">
                <div className="d-flex justify-content-between align-items-center mb-3">
                  <h5 className="mb-0">Recent Complaints</h5>
                  <Link to="/complaints" className="btn btn-sm btn-outline-primary">
                    Open list
                  </Link>
                </div>

                {loading ? (
                  <p className="text-muted mb-0">Loading recent activity...</p>
                ) : complaints.length === 0 ? (
                  <div className="alert alert-info mb-0">No complaints yet. Start by adding one.</div>
                ) : (
                  <div className="table-responsive">
                    <table className="table align-middle mb-0">
                      <thead>
                        <tr>
                          <th>Title</th>
                          <th>Status</th>
                          <th>Created</th>
                        </tr>
                      </thead>
                      <tbody>
                        {complaints.slice(0, 6).map((item) => (
                          <tr key={item._id}>
                            <td>{item.title || "Untitled complaint"}</td>
                            <td>
                              <span
                                className={`badge ${
                                  item.status === "Resolved"
                                    ? "text-bg-success"
                                    : "text-bg-warning"
                                }`}
                              >
                                {item.status || "Pending"}
                              </span>
                            </td>
                            <td>{formatDate(item.createdAt)}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>

            <div className="col-lg-4">
              <div className="panel-card">
                <h5 className="mb-3">Quick Actions</h5>
                <div className="d-grid gap-2">
                  <Link className="btn btn-primary" to="/complaints/add">
                    Add Complaint
                  </Link>
                  <Link className="btn btn-outline-primary" to="/complaints">
                    View My Complaints
                  </Link>
                  {isAdmin && (
                    <Link className="btn btn-outline-dark" to="/admin/complaints">
                      Open Admin Panel
                    </Link>
                  )}
                </div>

                <hr />
                <p className="text-muted small mb-1">Attachments Submitted</p>
                <h5 className="mb-0">{summary.withAttachments}</h5>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}

export default Dashboard;
